/**
 * Bounding box object
 */
export type BBox = {
    /**
     * Start x coordinate
     */
    minX: number;
    /**
     * End x coordinate
     */
    maxX: number;
    /**
     * Start y coordinate
     */
    minY: number;
    /**
     * End y coordinate
     */
    maxY: number;
};
/**
 * Check if a 2D or 1D point is within a rectangle or range
 * @param {[number, number]} point - The point defined as a tuple of [x, y]
 *   coordinates.
 * @param {[number, number, number, number]} rectangle - The rectangle defined
 *   as a quadruple of [minX, maxX, minY, maxY] coordinates.
 * @return {Boolean} If `true` the [x,y] point is in the rectangle.
 */
export function isPointHalfwayInRect([x, y]: [number, number], [minX, maxX, minY, maxY]: [number, number, number, number]): boolean;
/**
 * From: https://wrf.ecse.rpi.edu//Research/Short_Notes/pnpoly.html
 * @param {[number, number]} point - The point defined as a tuple of [x, y]
 *   coordinates.
 * @param {number[]} polygon - 1D list of vertices defining the polygon.
 * @return {Boolean} If `true` point lies within the polygon.
 */
export function isPointInPolygon([px, py]?: [number, number], polygon?: number[]): boolean;
/**
 * Check if a 2D or 1D point is within a rectangle or range
 * @param {[number, number]} point - The point defined as a tuple of [x, y]
 *   coordinates.
 * @param {[number, number, number, number]} rectangle - The rectangle defined
 *   as a quadruple of [minX, maxX, minY, maxY] coordinates.
 * @return {Boolean} If `true` the [x,y] point is in the rectangle.
 */
export function isPointInRect([x, y]: [number, number], [minX, maxX, minY, maxY]: [number, number, number, number]): boolean;
/**
 * L1 distance between a pair of points
 *
 * @description
 * Identical but much faster than `l1Dist([fromX, fromY], [toX, toY])`
 *
 * @param {number} fromX - X coordinate of the first point
 * @param {number} fromY - Y coordinate of the first point
 * @param {number} toX - X coordinate of the second point
 * @param {number} toY - Y coordinate of the first point
 * @return {number} L1 distance
 */
export function l1PointDist(fromX: number, fromY: number, toX: number, toY: number): number;
/**
 * L2 distance between a pair of points
 *
 * @description
 * Identical but much faster than `l2Dist([fromX, fromY], [toX, toY])`
 *
 * @param {number} fromX - X coordinate of the first point
 * @param {number} fromY - Y coordinate of the first point
 * @param {number} toX - X coordinate of the second point
 * @param {number} toY - Y coordinate of the first point
 * @return {number} L2 distance
 */
export function l2PointDist(fromX: number, fromY: number, toX: number, toY: number): number;
/**
 * L distance between a pair of vectors
 *
 * @description
 * Identical but much faster than `lDist(l)([fromX, fromY], [toX, toY])`
 *
 * @param {number} l - Defines the Lp space
 */
export function lPointDist(l: number): (fromX: number, fromY: number, toX: number, toY: number) => any[];
/**
 * @typedef {Object} BBox Bounding box object
 * @property {number} minX Start x coordinate
 * @property {number} maxX End x coordinate
 * @property {number} minY Start y coordinate
 * @property {number} maxY End y coordinate
 */
/**
 * L distance between a pair of rectangles
 *
 * @param {number} l - Defines the Lp space
 */
export function lRectDist(l: number): (bBox1: object, bBox2: object) => number;
